import numpy as np

def select_next_node(cur_truck_pos, depot_pos, all_truck_pos, unvisited_customers, current_time, truck_speed, time_windows):
    def calculate_travel_time(point1, point2):
        return np.linalg.norm(point2 - point1) / truck_speed

    def strategic_time_priority(window, arrival):
        # Calculate priority based on how soon the window starts after current arrival
        return max(0, window[0] - arrival)

    def adapt_distance_penalty(distance, average_distance):
        # Penalty increases if the distance is greater than average to discourage long detours
        return (distance / average_distance)

    average_distance = np.mean([np.linalg.norm(cust - cur_truck_pos) for cust in unvisited_customers])
    best_node = None
    best_score = float('inf')

    # calculate the aggregate scores for each customer based on urgency, distance penalty
    for i, customer_pos in enumerate(unvisited_customers):
        travel_time = calculate_travel_time(cur_truck_pos, customer_pos)
        arrival_time = current_time + travel_time
        window_start, window_end = time_windows[i]

        if arrival_time > window_end:
            continue  # Ignore customers that can't be reached in time

        urgency_penalty = strategic_time_priority(time_windows[i], arrival_time)
        distance_penalty = adapt_distance_penalty(travel_time, average_distance)

        score = (urgency_penalty * 1.5) + (distance_penalty * 0.5)

        if score < best_score:
            best_score = score
            best_node = i

    return best_node
